import{_ as t,o as a,c as o,ae as i}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Deepviews Overview","description":"","frontmatter":{"title":"Deepviews Overview","slug":"deepviews"},"headers":[],"relativePath":"marketer-hub/deepviews.md","filePath":"marketer-hub/deepviews.md"}'),r={name:"marketer-hub/deepviews.md"};function n(s,e,d,l,p,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>A Deepview is a mobile web splash page, hosted by Branch, that gives a preview of the in-app content behind a given Branch Link. When a visitor opens one of your Branch Links and does not have your app installed, you can show them a Deepview instead of sending them directly to the App/Play Store.</p><p>Deepviews are discoverable in all search portals (Google, Apple Spotlight, Bing, etc), opening up new mechanisms for people to find your app, and driving much higher conversions to install than sending visitors to the App/Play Store directly. Here&#39;s an example flow:</p><p><em>[Image: 243]</em></p><h3 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h3><p>Access to the Deepviews feature requires a premium plan. Please contact our <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">Sales team</a> to learn more about pricing and availability.</p><h3 id="deepview-types" tabindex="-1">Deepview Types <a class="header-anchor" href="#deepview-types" aria-label="Permalink to &quot;Deepview Types&quot;">​</a></h3><details><summary>Active Deepviews</summary><p>Active deepviews should only show when the app is <em>not</em> installed (or when direct deep linking doesn&#39;t work like in the Facebook webview), and pause on the deepview page. These let the user preview the content, ultimately deciding if they want to install the app. The user must click the call-to-action of <strong>Get The App</strong> in order to be sent to the appropriate App or Play Store page.</p><table tabindex="0"><thead><tr><th>Key</th><th>Value</th><th>Default Template</th></tr></thead><tbody><tr><td><code>$ios_deepview</code></td><td>The name of the template to use for iOS.</td><td><code>default_template</code></td></tr><tr><td><code>$android_deepview</code></td><td>The name of the template to use for Android.</td><td><code>default_template</code></td></tr><tr><td><code>$desktop_deepview</code></td><td>The name of the template to use for the desktop.</td><td><code>default_template</code></td></tr></tbody></table></details><details><summary>Passive Deepviews</summary><p>Passive deepviews should also only appear when the app is <em>not</em> installed, but instead of pausing on the deepview page, they will attempt to redirect to the App/Play Store immediately without the user taking action. These should be used when you don&#39;t want a blank white screen to be left in a browser after the user clicks a link to go install your app. Note that these are automatically enabled in Safari iOS 10.3 and Facebook iOS webviews if you&#39;re attempting to redirect to your Store page.</p><p>To disable passive deepviews, simply set the value to <code>false</code> in the link data.</p><table tabindex="0"><thead><tr><th>Key</th><th>Value</th><th>Default</th></tr></thead><tbody><tr><td><code>$ios_passive_deepview</code></td><td>The name of the template to use for iOS.</td><td><code>default_template</code></td></tr><tr><td><code>$android_passive_deepview</code></td><td>The name of the template to use for Android.</td><td><code>default_template</code></td></tr></tbody></table><p>To enable another template as the default passive deepview, select the &#39;Set as Passive Default&#39; option. You can also change the template <strong>on a link level</strong> by providing the template name in the <a href="./creating-a-deep-link.html#deepview">control parameters</a>. If you&#39;re creating a link by appending query parameters, you simply need to append the parameters to the URL. Please make sure to URL encode everything, lest the link will break.</p></details><details><summary>NativeLink™ Deepviews</summary><p>NativeLink™ is an innovation from Branch that bridges the gap created by Private Relay with an on-device solution that does not require the use of an IP address for deferred deep linking. NativeLink™ gives end-users the choice to copy deep link content to their clipboard or not, so they have full control of their user experience.</p><p>View the full guide on NativeLink™ Deepviews <a href="./nativelink-deferred-deep-linking.html"><strong>here</strong></a>.</p></details><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><ol><li>User clicks a Branch Link.</li><li>The web browser opens and displays a page that gives preview of the in-app content.</li><li>User clicks the App Download call-to-action button.</li><li>User is deep linked into in-app content when they open the app after download.</li></ol>',12)])])}const v=t(r,[["render",n]]);export{u as __pageData,v as default};
